export interface Product {
  id: string;
  name: string;
  description: string;
  unitPrice: number;
  image?: string; // base64 string
}

export interface QuoteItem {
  productId: string;
  name: string;
  description: string;
  unitPrice: number;
  quantity: number;
  lineTotal: number;
  image?: string; // base64 string
}

export interface Quotation {
  id: string;
  quoteNumber: string;
  date: string;
  clientName: string;
  clientEmail?: string;
  clientAddress?: string;
  items: QuoteItem[];
  subtotal: number;
  taxRate: number; // e.g., 0.05 for 5%
  taxAmount: number;
  total: number;
}

import React, { useState, useEffect, useRef } from 'react';
import Input from './Input';
import Textarea from './Textarea';
import Button from './Button';
import { Product } from '../types';

interface ProductFormProps {
  onSave: (product: Product) => void;
  onCancel: () => void;
  editingProduct?: Product | null;
}

const ProductForm: React.FC<ProductFormProps> = ({ onSave, onCancel, editingProduct }) => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [unitPrice, setUnitPrice] = useState<string>('');
  const [image, setImage] = useState<string | undefined>(undefined);
  const [errors, setErrors] = useState<{ [key: string]: string }>({});
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (editingProduct) {
      setName(editingProduct.name);
      setDescription(editingProduct.description);
      setUnitPrice(editingProduct.unitPrice.toString());
      setImage(editingProduct.image);
    } else {
      setName('');
      setDescription('');
      setUnitPrice('');
      setImage(undefined);
    }
    setErrors({});
  }, [editingProduct]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const validate = () => {
    const newErrors: { [key: string]: string } = {};
    if (!name.trim()) newErrors.name = 'Product name is required.';
    if (!unitPrice) {
      newErrors.unitPrice = 'Unit price is required.';
    } else if (isNaN(parseFloat(unitPrice)) || parseFloat(unitPrice) <= 0) {
      newErrors.unitPrice = 'Unit price must be a positive number.';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      const newProduct: Product = {
        id: editingProduct ? editingProduct.id : Date.now().toString(),
        name,
        description,
        unitPrice: parseFloat(unitPrice),
        image,
      };
      onSave(newProduct);
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-md max-w-lg mx-auto mb-8 border border-gray-100">
      <h2 className="text-2xl font-bold mb-6 text-center text-gray-800">
        {editingProduct ? 'Edit Product' : 'Add New Product'}
      </h2>
      <form onSubmit={handleSubmit}>
        <div className="flex flex-col items-center mb-6">
          <div className="w-32 h-32 bg-gray-100 rounded-lg border-2 border-dashed border-gray-300 flex items-center justify-center overflow-hidden mb-3">
            {image ? (
              <img src={image} alt="Preview" className="w-full h-full object-cover" />
            ) : (
              <svg className="w-12 h-12 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
            )}
          </div>
          <input
            type="file"
            ref={fileInputRef}
            className="hidden"
            accept="image/*"
            onChange={handleImageChange}
          />
          <Button 
            type="button" 
            variant="outline" 
            size="sm" 
            onClick={() => fileInputRef.current?.click()}
          >
            {image ? 'Change Photo' : 'Upload Photo'}
          </Button>
          {image && (
            <button 
              type="button" 
              className="text-red-500 text-xs mt-2 hover:underline"
              onClick={() => setImage(undefined)}
            >
              Remove Photo
            </button>
          )}
        </div>

        <Input
          id="productName"
          label="Product Name"
          type="text"
          value={name}
          onChange={(e) => setName(e.target.value)}
          placeholder="e.g., Custom Software Development"
          error={errors.name}
        />
        <Textarea
          id="productDescription"
          label="Description"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          placeholder="Detailed description of the product or service."
        />
        <Input
          id="unitPrice"
          label="Unit Price (₹)"
          type="number"
          step="0.01"
          value={unitPrice}
          onChange={(e) => setUnitPrice(e.target.value)}
          placeholder="e.g., 500.00"
          error={errors.unitPrice}
        />
        <div className="flex justify-end space-x-3 mt-6">
          <Button type="button" variant="secondary" onClick={onCancel}>
            Cancel
          </Button>
          <Button type="submit" variant="primary">
            {editingProduct ? 'Update Product' : 'Add Product'}
          </Button>
        </div>
      </form>
    </div>
  );
};

export default ProductForm;

