import React, { useState } from 'react';
import { Product, QuoteItem, Quotation } from '../types';
import Input from './Input';
import Textarea from './Textarea';
import Button from './Button';

interface QuoteBuilderProps {
  products: Product[];
  onGenerateQuote: (quotation: Quotation) => void;
}

const QuoteBuilder: React.FC<QuoteBuilderProps> = ({ products, onGenerateQuote }) => {
  const [clientName, setClientName] = useState('');
  const [clientEmail, setClientEmail] = useState('');
  const [clientAddress, setClientAddress] = useState('');
  const [taxRate, setTaxRate] = useState<string>('0.05');
  const [selectedItems, setSelectedItems] = useState<Map<string, { product: Product; quantity: number }>>(new Map());
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const handleAddItem = (product: Product) => {
    setSelectedItems((prev) => {
      const newItems = new Map(prev);
      const existing = newItems.get(product.id);
      if (existing) {
        newItems.set(product.id, { product: existing.product, quantity: existing.quantity + 1 });
      } else {
        newItems.set(product.id, { product, quantity: 1 });
      }
      return newItems;
    });
  };

  const handleUpdateQuantity = (productId: string, quantity: number) => {
    setSelectedItems((prev) => {
      const newItems = new Map(prev);
      const existing = newItems.get(productId);
      if (existing) {
        if (quantity <= 0) {
          newItems.delete(productId);
        } else {
          newItems.set(productId, { product: existing.product, quantity });
        }
      }
      return newItems;
    });
  };

  const handleRemoveItem = (productId: string) => {
    setSelectedItems((prev) => {
      const newItems = new Map(prev);
      newItems.delete(productId);
      return newItems;
    });
  };

  const validate = () => {
    const newErrors: { [key: string]: string } = {};
    if (!clientName.trim()) newErrors.clientName = 'Client name is required.';
    if (selectedItems.size === 0) newErrors.items = 'At least one product must be added to the quotation.';
    if (isNaN(parseFloat(taxRate)) || parseFloat(taxRate) < 0) {
      newErrors.taxRate = 'Tax rate must be a non-negative number.';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const generateQuote = () => {
    if (!validate()) {
      alert('Please correct the errors before generating the quote.');
      return;
    }

    const items: QuoteItem[] = Array.from(selectedItems.values()).map(({ product, quantity }) => ({
      productId: product.id,
      name: product.name,
      description: product.description,
      unitPrice: product.unitPrice,
      quantity,
      lineTotal: product.unitPrice * quantity,
      image: product.image,
    }));

    const subtotal = items.reduce((sum: number, item: QuoteItem) => sum + item.lineTotal, 0);
    const parsedTaxRate = parseFloat(taxRate);
    const taxAmount = subtotal * parsedTaxRate;
    const total = subtotal + taxAmount;

    const newQuotation: Quotation = {
      id: Date.now().toString(),
      quoteNumber: `Q-${Date.now().toString().slice(-6)}`,
      date: new Date().toLocaleDateString('en-IN'),
      clientName,
      clientEmail: clientEmail.trim() || undefined,
      clientAddress: clientAddress.trim() || undefined,
      items,
      subtotal,
      taxRate: parsedTaxRate,
      taxAmount,
      total,
    };

    onGenerateQuote(newQuotation);
    setClientName('');
    setClientEmail('');
    setClientAddress('');
    setTaxRate('0.05');
    setSelectedItems(new Map());
    setErrors({});
  };

  const currentQuoteItems = Array.from(selectedItems.values());
  const subtotal = currentQuoteItems.reduce((sum, { product, quantity }) => sum + product.unitPrice * quantity, 0);
  const parsedTaxRate = parseFloat(taxRate);
  const taxAmount = subtotal * (isNaN(parsedTaxRate) ? 0 : parsedTaxRate);
  const total = subtotal + taxAmount;

  return (
    <div className="bg-white p-6 rounded-lg shadow-md mb-8 border border-gray-100">
      <h2 className="text-2xl font-bold mb-6 text-center text-gray-800">Create New Quotation</h2>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700">Client Details</h3>
        <Input
          id="clientName"
          label="Client Name"
          type="text"
          value={clientName}
          onChange={(e) => setClientName(e.target.value)}
          placeholder="e.g., Acme Corp."
          error={errors.clientName}
        />
        <Input
          id="clientEmail"
          label="Client Email (Optional)"
          type="email"
          value={clientEmail}
          onChange={(e) => setClientEmail(e.target.value)}
          placeholder="e.g., contact@acmecorp.com"
        />
        <Textarea
          id="clientAddress"
          label="Client Address (Optional)"
          value={clientAddress}
          onChange={(e) => setClientAddress(e.target.value)}
          placeholder="123 Main St, Anytown, India"
        />
      </section>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700">Available Products</h3>
        {products.length === 0 ? (
          <p className="text-gray-600">No products available. Please add products in the 'Manage Products' section.</p>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {products.map((product) => (
              <div key={product.id} className="border border-gray-200 p-4 rounded-lg flex flex-col justify-between hover:border-blue-300 transition-colors bg-gray-50">
                <div>
                  <div className="w-full h-32 bg-gray-200 rounded-md mb-3 overflow-hidden">
                    {product.image ? (
                      <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-gray-400 bg-gray-100">
                        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                        </svg>
                      </div>
                    )}
                  </div>
                  <h4 className="font-medium text-lg text-gray-900 line-clamp-1">{product.name}</h4>
                  <p className="text-xs text-gray-600 mb-2 line-clamp-2">{product.description || 'No description'}</p>
                  <p className="text-md font-bold text-blue-700">₹{product.unitPrice.toFixed(2)}</p>
                </div>
                <Button size="sm" onClick={() => handleAddItem(product)} className="mt-4 w-full">
                  Add to Quote
                </Button>
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700">Current Quote Items</h3>
        {errors.items && <p className="mb-4 text-sm text-red-600 font-medium">{errors.items}</p>}
        {selectedItems.size === 0 ? (
          <p className="text-gray-600 italic">No items added to the quote yet.</p>
        ) : (
          <div className="overflow-x-auto border border-gray-100 rounded-lg">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Product
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Unit Price
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Quantity
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Line Total
                  </th>
                  <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {currentQuoteItems.map(({ product, quantity }) => (
                  <tr key={product.id}>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      <div className="flex items-center">
                        <div className="h-8 w-8 rounded overflow-hidden mr-3 border border-gray-200 bg-gray-50 flex-shrink-0">
                          {product.image ? (
                            <img src={product.image} alt="" className="h-full w-full object-cover" />
                          ) : (
                            <div className="h-full w-full flex items-center justify-center text-gray-400">
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                              </svg>
                            </div>
                          )}
                        </div>
                        {product.name}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      ₹{product.unitPrice.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      <Input
                        id={`quantity-${product.id}`}
                        type="number"
                        min="1"
                        value={quantity.toString()}
                        onChange={(e) => handleUpdateQuantity(product.id, parseInt(e.target.value) || 0)}
                        className="w-20 p-1 text-center"
                        label=""
                      />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-semibold">
                      ₹{(product.unitPrice * quantity).toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <Button variant="danger" size="sm" onClick={() => handleRemoveItem(product.id)}>
                        Remove
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>

      <section>
        <div className="flex justify-end mb-4">
          <div className="w-full md:w-1/2 lg:w-1/3 bg-gray-50 p-4 rounded-lg border border-gray-200">
            <div className="flex justify-between items-center text-gray-700 py-1">
              <span className="font-semibold">Subtotal:</span>
              <span className="font-bold">₹{subtotal.toFixed(2)}</span>
            </div>
            <Input
              id="taxRate"
              label="Tax Rate (%)"
              type="number"
              step="0.01"
              min="0"
              value={(parseFloat(taxRate) * 100).toFixed(2)}
              onChange={(e) => setTaxRate((parseFloat(e.target.value) / 100).toFixed(4))}
              className="w-full py-1"
              error={errors.taxRate}
            />
            <div className="flex justify-between items-center text-gray-700 py-1">
              <span className="font-semibold">Tax Amount:</span>
              <span>₹{taxAmount.toFixed(2)}</span>
            </div>
            <div className="flex justify-between items-center text-2xl font-bold text-blue-700 py-2 border-t-2 border-gray-300 mt-2">
              <span>Total:</span>
              <span>₹{total.toFixed(2)}</span>
            </div>
          </div>
        </div>
        <div className="flex justify-center mt-6">
          <Button variant="primary" size="lg" onClick={generateQuote}>
            Generate Quotation
          </Button>
        </div>
      </section>
    </div>
  );
};

export default QuoteBuilder;

import React, { useState, useEffect, useCallback } from 'react';
import ReactDOM from 'react-dom/client';
import { Product, Quotation } from './types';
import { LOCAL_STORAGE_PRODUCTS_KEY, LOCAL_STORAGE_QUOTATIONS_KEY } from './constants';
import ProductForm from './components/ProductForm';
import ProductList from './components/ProductList';
import QuoteBuilder from './components/QuoteBuilder';
import QuoteDisplay from './components/QuoteDisplay';
import Button from './components/Button';

enum View {
  PRODUCTS = 'products',
  CREATE_QUOTE = 'create-quote',
  VIEW_QUOTE = 'view-quote',
  ALL_QUOTES = 'all-quotes',
}

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [quotations, setQuotations] = useState<Quotation[]>([]);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [currentView, setCurrentView] = useState<View>(View.PRODUCTS);
  const [selectedQuotation, setSelectedQuotation] = useState<Quotation | null>(null);

  useEffect(() => {
    try {
      const storedProducts = localStorage.getItem(LOCAL_STORAGE_PRODUCTS_KEY);
      if (storedProducts) {
        setProducts(JSON.parse(storedProducts));
      }
    } catch (error) {
      console.error('Failed to load products from local storage:', error);
    }

    try {
      const storedQuotations = localStorage.getItem(LOCAL_STORAGE_QUOTATIONS_KEY);
      if (storedQuotations) {
        setQuotations(JSON.parse(storedQuotations));
      }
    } catch (error) {
      console.error('Failed to load quotations from local storage:', error);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_PRODUCTS_KEY, JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_QUOTATIONS_KEY, JSON.stringify(quotations));
  }, [quotations]);

  const handleAddOrUpdateProduct = useCallback((product: Product) => {
    setProducts((prevProducts) => {
      const existingIndex = prevProducts.findIndex((p) => p.id === product.id);
      if (existingIndex > -1) {
        const updatedProducts = [...prevProducts];
        updatedProducts[existingIndex] = product;
        return updatedProducts;
      } else {
        return [...prevProducts, product];
      }
    });
    setEditingProduct(null);
    setCurrentView(View.PRODUCTS);
  }, []);

  const handleDeleteProduct = useCallback((id: string) => {
    if (window.confirm('Are you sure you want to delete this product? It will be removed from all future quotes.')) {
      setProducts((prevProducts) => prevProducts.filter((p) => p.id !== id));
    }
  }, []);

  const handleGenerateQuotation = useCallback((quotation: Quotation) => {
    setQuotations((prevQuotations) => [...prevQuotations, quotation]);
    setSelectedQuotation(quotation);
    setCurrentView(View.VIEW_QUOTE);
  }, []);

  const handleEditProduct = useCallback((product: Product) => {
    setEditingProduct(product);
    setCurrentView(View.PRODUCTS);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, []);

  const handleViewQuote = useCallback((quote: Quotation) => {
    setSelectedQuotation(quote);
    setCurrentView(View.VIEW_QUOTE);
  }, []);

  const handleBackToBuilder = useCallback(() => {
    setSelectedQuotation(null);
    setCurrentView(View.CREATE_QUOTE);
  }, []);

  const handleDeleteQuotation = useCallback((id: string) => {
    if (window.confirm('Are you sure you want to delete this quotation?')) {
      setQuotations((prevQuotations) => prevQuotations.filter((q) => q.id !== id));
    }
  }, []);

  return (
    <div className="min-h-screen bg-gray-100 pb-16">
      <header className="bg-gradient-to-r from-blue-700 to-blue-900 text-white p-6 shadow-md sticky top-0 z-10">
        <div className="container mx-auto flex flex-col md:flex-row justify-between items-center">
          <div className="flex items-center mb-4 md:mb-0">
             <svg className="w-8 h-8 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
             </svg>
             <h1 className="text-3xl font-extrabold tracking-tight">QuoteFlow</h1>
          </div>
          <nav className="flex flex-wrap justify-center gap-2 sm:gap-4">
            <Button
              variant={currentView === View.PRODUCTS ? 'secondary' : 'outline'}
              className={currentView === View.PRODUCTS ? 'bg-white text-blue-800' : 'text-white border-white hover:bg-white/10'}
              onClick={() => {
                setCurrentView(View.PRODUCTS);
                setEditingProduct(null);
              }}
            >
              Manage Products
            </Button>
            <Button
              variant={currentView === View.CREATE_QUOTE ? 'secondary' : 'outline'}
              className={currentView === View.CREATE_QUOTE ? 'bg-white text-blue-800' : 'text-white border-white hover:bg-white/10'}
              onClick={() => setCurrentView(View.CREATE_QUOTE)}
            >
              Create Quotation
            </Button>
            <Button
              variant={currentView === View.ALL_QUOTES ? 'secondary' : 'outline'}
              className={currentView === View.ALL_QUOTES ? 'bg-white text-blue-800' : 'text-white border-white hover:bg-white/10'}
              onClick={() => setCurrentView(View.ALL_QUOTES)}
            >
              All Quotations
            </Button>
          </nav>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8">
        {currentView === View.PRODUCTS && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <ProductForm
              onSave={handleAddOrUpdateProduct}
              onCancel={() => setEditingProduct(null)}
              editingProduct={editingProduct}
            />
            <ProductList
              products={products}
              onEdit={handleEditProduct}
              onDelete={handleDeleteProduct}
            />
          </div>
        )}

        {currentView === View.CREATE_QUOTE && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <QuoteBuilder products={products} onGenerateQuote={handleGenerateQuotation} />
          </div>
        )}

        {currentView === View.VIEW_QUOTE && selectedQuotation && (
          <div className="animate-in zoom-in duration-300">
             <QuoteDisplay quotation={selectedQuotation} onBack={handleBackToBuilder} />
          </div>
        )}

        {currentView === View.ALL_QUOTES && (
          <div className="bg-white p-6 rounded-lg shadow-md overflow-x-auto border border-gray-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-2xl font-bold mb-6 text-center text-gray-800">All Generated Quotations</h2>
            {quotations.length === 0 ? (
              <div className="text-center py-12">
                <p className="text-gray-500 text-lg mb-4">No quotations generated yet.</p>
                <Button onClick={() => setCurrentView(View.CREATE_QUOTE)}>Create Your First Quote</Button>
              </div>
            ) : (
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Quote #
                    </th>
                    <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Date
                    </th>
                    <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Client Name
                    </th>
                    <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Total
                    </th>
                    <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Actions
                    </th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {quotations.map((quote) => (
                    <tr key={quote.id} className="hover:bg-blue-50/50 transition-colors">
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-bold text-blue-700 cursor-pointer hover:underline"
                          onClick={() => handleViewQuote(quote)}>
                        {quote.quoteNumber}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                        {quote.date}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-medium">
                        {quote.clientName}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-right text-sm text-gray-900 font-bold">
                        ₹{quote.total.toFixed(2)}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                        <Button variant="secondary" size="sm" onClick={() => handleViewQuote(quote)} className="mr-2">
                          View
                        </Button>
                        <Button variant="danger" size="sm" onClick={() => handleDeleteQuotation(quote.id)}>
                          Delete
                        </Button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export interface Product {
  id: string;
  name: string;
  description: string;
  unitPrice: number;
  image?: string; // base64 string
}

export interface QuoteItem {
  productId: string;
  name: string;
  description: string;
  unitPrice: number;
  quantity: number;
  lineTotal: number;
  image?: string; // base64 string
}

export interface Quotation {
  id: string;
  quoteNumber: string;
  date: string;
  clientName: string;
  clientEmail?: string;
  clientAddress?: string;
  items: QuoteItem[];
  subtotal: number;
  taxRate: number; // e.g., 0.05 for 5%
  taxAmount: number;
  freightCost: number;
  total: number;
}

import React, { useState } from 'react';
import { Product, QuoteItem, Quotation } from '../types';
import Input from './Input';
import Textarea from './Textarea';
import Button from './Button';

interface QuoteBuilderProps {
  products: Product[];
  onGenerateQuote: (quotation: Quotation) => void;
}

const QuoteBuilder: React.FC<QuoteBuilderProps> = ({ products, onGenerateQuote }) => {
  const [clientName, setClientName] = useState('');
  const [clientEmail, setClientEmail] = useState('');
  const [clientAddress, setClientAddress] = useState('');
  const [taxRate, setTaxRate] = useState<string>('0.05');
  const [freightCost, setFreightCost] = useState<string>('0');
  const [selectedItems, setSelectedItems] = useState<Map<string, { product: Product; quantity: number }>>(new Map());
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const handleAddItem = (product: Product) => {
    setSelectedItems((prev) => {
      const newItems = new Map(prev);
      const existing = newItems.get(product.id);
      if (existing) {
        newItems.set(product.id, { product: existing.product, quantity: existing.quantity + 1 });
      } else {
        newItems.set(product.id, { product, quantity: 1 });
      }
      return newItems;
    });
  };

  const handleUpdateQuantity = (productId: string, quantity: number) => {
    setSelectedItems((prev) => {
      const newItems = new Map(prev);
      const existing = newItems.get(productId);
      if (existing) {
        if (quantity <= 0) {
          newItems.delete(productId);
        } else {
          newItems.set(productId, { product: existing.product, quantity });
        }
      }
      return newItems;
    });
  };

  const handleRemoveItem = (productId: string) => {
    setSelectedItems((prev) => {
      const newItems = new Map(prev);
      newItems.delete(productId);
      return newItems;
    });
  };

  const validate = () => {
    const newErrors: { [key: string]: string } = {};
    if (!clientName.trim()) newErrors.clientName = 'Client name is required.';
    if (selectedItems.size === 0) newErrors.items = 'At least one product must be added to the quotation.';
    if (isNaN(parseFloat(taxRate)) || parseFloat(taxRate) < 0) {
      newErrors.taxRate = 'Tax rate must be a non-negative number.';
    }
    if (isNaN(parseFloat(freightCost)) || parseFloat(freightCost) < 0) {
      newErrors.freightCost = 'Freight cost must be a non-negative number.';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const generateQuote = () => {
    if (!validate()) {
      alert('Please correct the errors before generating the quote.');
      return;
    }

    const items: QuoteItem[] = Array.from(selectedItems.values()).map(({ product, quantity }) => ({
      productId: product.id,
      name: product.name,
      description: product.description,
      unitPrice: product.unitPrice,
      quantity,
      lineTotal: product.unitPrice * quantity,
      image: product.image,
    }));

    const subtotal = items.reduce((sum: number, item: QuoteItem) => sum + item.lineTotal, 0);
    const parsedTaxRate = parseFloat(taxRate);
    const parsedFreight = parseFloat(freightCost) || 0;
    const taxAmount = subtotal * parsedTaxRate;
    const total = subtotal + taxAmount + parsedFreight;

    const newQuotation: Quotation = {
      id: Date.now().toString(),
      quoteNumber: `Q-${Date.now().toString().slice(-6)}`,
      date: new Date().toLocaleDateString('en-IN'),
      clientName,
      clientEmail: clientEmail.trim() || undefined,
      clientAddress: clientAddress.trim() || undefined,
      items,
      subtotal,
      taxRate: parsedTaxRate,
      taxAmount,
      freightCost: parsedFreight,
      total,
    };

    onGenerateQuote(newQuotation);
    setClientName('');
    setClientEmail('');
    setClientAddress('');
    setTaxRate('0.05');
    setFreightCost('0');
    setSelectedItems(new Map());
    setErrors({});
  };

  const currentQuoteItems = Array.from(selectedItems.values());
  const subtotal = currentQuoteItems.reduce((sum, { product, quantity }) => sum + product.unitPrice * quantity, 0);
  const parsedTaxRate = parseFloat(taxRate);
  const parsedFreightValue = parseFloat(freightCost);
  const taxAmount = subtotal * (isNaN(parsedTaxRate) ? 0 : parsedTaxRate);
  const total = subtotal + taxAmount + (isNaN(parsedFreightValue) ? 0 : parsedFreightValue);

  return (
    <div className="bg-white p-6 rounded-lg shadow-md mb-8 border border-gray-100">
      <h2 className="text-2xl font-bold mb-6 text-center text-gray-800">Create New Quotation</h2>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Client Details</h3>
        <Input
          id="clientName"
          label="Client Name"
          type="text"
          value={clientName}
          onChange={(e) => setClientName(e.target.value)}
          placeholder="e.g., Acme Corp."
          error={errors.clientName}
        />
        <Input
          id="clientEmail"
          label="Client Email (Optional)"
          type="email"
          value={clientEmail}
          onChange={(e) => setClientEmail(e.target.value)}
          placeholder="e.g., contact@acmecorp.com"
        />
        <Textarea
          id="clientAddress"
          label="Client Address (Optional)"
          value={clientAddress}
          onChange={(e) => setClientAddress(e.target.value)}
          placeholder="123 Main St, Anytown, India"
        />
      </section>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Available Products</h3>
        {products.length === 0 ? (
          <p className="text-gray-600">No products available. Please add products in the 'Manage Products' section.</p>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {products.map((product) => (
              <div key={product.id} className="border border-gray-200 p-4 rounded-lg flex flex-col justify-between hover:border-blue-300 transition-colors bg-gray-50">
                <div>
                  <div className="w-full h-32 bg-gray-200 rounded-md mb-3 overflow-hidden">
                    {product.image ? (
                      <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-gray-400 bg-gray-100">
                        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                        </svg>
                      </div>
                    )}
                  </div>
                  <h4 className="font-medium text-lg text-gray-900 line-clamp-1">{product.name}</h4>
                  <p className="text-xs text-gray-600 mb-2 line-clamp-2">{product.description || 'No description'}</p>
                  <p className="text-md font-bold text-blue-700">₹{product.unitPrice.toFixed(2)}</p>
                </div>
                <Button size="sm" onClick={() => handleAddItem(product)} className="mt-4 w-full">
                  Add to Quote
                </Button>
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Current Quote Items</h3>
        {errors.items && <p className="mb-4 text-sm text-red-600 font-medium">{errors.items}</p>}
        {selectedItems.size === 0 ? (
          <p className="text-gray-600 italic">No items added to the quote yet.</p>
        ) : (
          <div className="overflow-x-auto border border-gray-100 rounded-lg">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Product
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Unit Price
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Quantity
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Line Total
                  </th>
                  <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {currentQuoteItems.map(({ product, quantity }) => (
                  <tr key={product.id}>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      <div className="flex items-center">
                        <div className="h-8 w-8 rounded overflow-hidden mr-3 border border-gray-200 bg-gray-50 flex-shrink-0">
                          {product.image ? (
                            <img src={product.image} alt="" className="h-full w-full object-cover" />
                          ) : (
                            <div className="h-full w-full flex items-center justify-center text-gray-400">
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                              </svg>
                            </div>
                          )}
                        </div>
                        {product.name}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      ₹{product.unitPrice.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      <Input
                        id={`quantity-${product.id}`}
                        type="number"
                        min="1"
                        value={quantity.toString()}
                        onChange={(e) => handleUpdateQuantity(product.id, parseInt(e.target.value) || 0)}
                        className="w-20 p-1 text-center"
                        label=""
                      />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-semibold">
                      ₹{(product.unitPrice * quantity).toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <Button variant="danger" size="sm" onClick={() => handleRemoveItem(product.id)}>
                        Remove
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>

      <section>
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Quote Summary</h3>
        <div className="flex justify-end mb-4">
          <div className="w-full md:w-1/2 lg:w-1/3 bg-gray-50 p-6 rounded-lg border border-gray-200 shadow-inner">
            <div className="flex justify-between items-center text-gray-700 py-2 border-b border-gray-200">
              <span className="font-semibold">Subtotal:</span>
              <span className="font-bold">₹{subtotal.toFixed(2)}</span>
            </div>

            <div className="py-2 border-b border-gray-200">
              <Input
                id="taxRate"
                label="Tax Rate (%)"
                type="number"
                step="0.01"
                min="0"
                value={(parseFloat(taxRate) * 100).toFixed(2)}
                onChange={(e) => setTaxRate((parseFloat(e.target.value) / 100).toFixed(4))}
                className="mb-0"
                error={errors.taxRate}
              />
              <div className="flex justify-between items-center text-gray-600 text-sm mt-1">
                <span>Tax Amount:</span>
                <span>₹{taxAmount.toFixed(2)}</span>
              </div>
            </div>

            <div className="py-2 border-b border-gray-200">
              <Input
                id="freightCost"
                label="Freight Cost (₹)"
                type="number"
                step="0.01"
                min="0"
                value={freightCost}
                onChange={(e) => setFreightCost(e.target.value)}
                className="mb-0"
                error={errors.freightCost}
                placeholder="0.00"
              />
            </div>

            <div className="flex justify-between items-center text-2xl font-bold text-blue-700 pt-4 mt-2">
              <span>Total:</span>
              <span>₹{total.toFixed(2)}</span>
            </div>
          </div>
        </div>
        <div className="flex justify-center mt-6">
          <Button variant="primary" size="lg" onClick={generateQuote}>
            Generate Quotation
          </Button>
        </div>
      </section>
    </div>
  );
};

