import React, { useState } from 'react';
import { Product, QuoteItem, Quotation } from '../types';
import Input from './Input';
import Textarea from './Textarea';
import Button from './Button';

interface QuoteBuilderProps {
  products: Product[];
  onGenerateQuote: (quotation: Quotation) => void;
}

const QuoteBuilder: React.FC<QuoteBuilderProps> = ({ products, onGenerateQuote }) => {
  const [clientName, setClientName] = useState('');
  const [clientEmail, setClientEmail] = useState('');
  const [clientAddress, setClientAddress] = useState('');
  const [taxRate, setTaxRate] = useState<string>('0.05');
  const [freightCost, setFreightCost] = useState<string>('0');
  const [selectedItems, setSelectedItems] = useState<Map<string, { product: Product; quantity: number }>>(new Map());
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const handleAddItem = (product: Product) => {
    setSelectedItems((prev) => {
      const newItems = new Map(prev);
      const existing = newItems.get(product.id);
      if (existing) {
        newItems.set(product.id, { product: existing.product, quantity: existing.quantity + 1 });
      } else {
        newItems.set(product.id, { product, quantity: 1 });
      }
      return newItems;
    });
  };

  const handleUpdateQuantity = (productId: string, quantity: number) => {
    setSelectedItems((prev) => {
      const newItems = new Map(prev);
      const existing = newItems.get(productId);
      if (existing) {
        if (quantity <= 0) {
          newItems.delete(productId);
        } else {
          newItems.set(productId, { product: existing.product, quantity });
        }
      }
      return newItems;
    });
  };

  const handleRemoveItem = (productId: string) => {
    setSelectedItems((prev) => {
      const newItems = new Map(prev);
      newItems.delete(productId);
      return newItems;
    });
  };

  const validate = () => {
    const newErrors: { [key: string]: string } = {};
    if (!clientName.trim()) newErrors.clientName = 'Client name is required.';
    if (selectedItems.size === 0) newErrors.items = 'At least one product must be added to the quotation.';
    if (isNaN(parseFloat(taxRate)) || parseFloat(taxRate) < 0) {
      newErrors.taxRate = 'Tax rate must be a non-negative number.';
    }
    if (isNaN(parseFloat(freightCost)) || parseFloat(freightCost) < 0) {
      newErrors.freightCost = 'Freight cost must be a non-negative number.';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const generateQuote = () => {
    if (!validate()) {
      alert('Please correct the errors before generating the quote.');
      return;
    }

    const items: QuoteItem[] = Array.from(selectedItems.values()).map(({ product, quantity }) => ({
      productId: product.id,
      name: product.name,
      description: product.description,
      unitPrice: product.unitPrice,
      quantity,
      lineTotal: product.unitPrice * quantity,
      image: product.image,
    }));

    const subtotal = items.reduce((sum: number, item: QuoteItem) => sum + item.lineTotal, 0);
    const parsedTaxRate = parseFloat(taxRate);
    const parsedFreight = parseFloat(freightCost) || 0;
    const taxAmount = subtotal * parsedTaxRate;
    const total = subtotal + taxAmount + parsedFreight;

    const newQuotation: Quotation = {
      id: Date.now().toString(),
      quoteNumber: `Q-${Date.now().toString().slice(-6)}`,
      date: new Date().toLocaleDateString('en-IN'),
      clientName,
      clientEmail: clientEmail.trim() || undefined,
      clientAddress: clientAddress.trim() || undefined,
      items,
      subtotal,
      taxRate: parsedTaxRate,
      taxAmount,
      freightCost: parsedFreight,
      total,
    };

    onGenerateQuote(newQuotation);
    setClientName('');
    setClientEmail('');
    setClientAddress('');
    setTaxRate('0.05');
    setFreightCost('0');
    setSelectedItems(new Map());
    setErrors({});
  };

  const currentQuoteItems = Array.from(selectedItems.values());
  const subtotal = currentQuoteItems.reduce((sum, { product, quantity }) => sum + product.unitPrice * quantity, 0);
  const parsedTaxRate = parseFloat(taxRate);
  const parsedFreightValue = parseFloat(freightCost);
  const taxAmount = subtotal * (isNaN(parsedTaxRate) ? 0 : parsedTaxRate);
  const total = subtotal + taxAmount + (isNaN(parsedFreightValue) ? 0 : parsedFreightValue);

  return (
    <div className="bg-white p-6 rounded-lg shadow-md mb-8 border border-gray-100">
      <h2 className="text-2xl font-bold mb-6 text-center text-gray-800">Create New Quotation</h2>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Client Details</h3>
        <Input
          id="clientName"
          label="Client Name"
          type="text"
          value={clientName}
          onChange={(e) => setClientName(e.target.value)}
          placeholder="e.g., Acme Corp."
          error={errors.clientName}
        />
        <Input
          id="clientEmail"
          label="Client Email (Optional)"
          type="email"
          value={clientEmail}
          onChange={(e) => setClientEmail(e.target.value)}
          placeholder="e.g., contact@acmecorp.com"
        />
        <Textarea
          id="clientAddress"
          label="Client Address (Optional)"
          value={clientAddress}
          onChange={(e) => setClientAddress(e.target.value)}
          placeholder="123 Main St, Anytown, India"
        />
      </section>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Available Products</h3>
        {products.length === 0 ? (
          <p className="text-gray-600">No products available. Please add products in the 'Manage Products' section.</p>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            {products.map((product) => (
              <div key={product.id} className="border border-gray-200 rounded-lg flex flex-col justify-between hover:border-blue-300 transition-colors bg-white overflow-hidden shadow-sm">
                <div className="relative pt-[177.77%] bg-gray-100 border-b border-gray-200">
                  <div className="absolute inset-0">
                    {product.image ? (
                      <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-gray-300">
                        <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                        </svg>
                      </div>
                    )}
                  </div>
                </div>
                <div className="p-4">
                  <h4 className="font-bold text-gray-900 truncate">{product.name}</h4>
                  <p className="text-xs text-gray-500 mb-2 line-clamp-1 h-4">{product.description || ''}</p>
                  <p className="text-lg font-extrabold text-blue-700">₹{product.unitPrice.toLocaleString('en-IN')}</p>
                  <Button size="sm" onClick={() => handleAddItem(product)} className="mt-4 w-full">
                    Add to Quote
                  </Button>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Current Quote Items</h3>
        {errors.items && <p className="mb-4 text-sm text-red-600 font-medium">{errors.items}</p>}
        {selectedItems.size === 0 ? (
          <p className="text-gray-600 italic">No items added to the quote yet.</p>
        ) : (
          <div className="overflow-x-auto border border-gray-100 rounded-lg">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Product
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Unit Price
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Quantity
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Line Total
                  </th>
                  <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {currentQuoteItems.map(({ product, quantity }) => (
                  <tr key={product.id}>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      <div className="flex items-center">
                        <div className="h-12 w-7 rounded overflow-hidden mr-3 border border-gray-200 bg-gray-50 flex-shrink-0">
                          {product.image ? (
                            <img src={product.image} alt="" className="h-full w-full object-cover" />
                          ) : (
                            <div className="h-full w-full flex items-center justify-center text-gray-300">
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                              </svg>
                            </div>
                          )}
                        </div>
                        {product.name}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      ₹{product.unitPrice.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      <Input
                        id={`quantity-${product.id}`}
                        type="number"
                        min="1"
                        value={quantity.toString()}
                        onChange={(e) => handleUpdateQuantity(product.id, parseInt(e.target.value) || 0)}
                        className="w-20 p-1 text-center mb-0"
                        label=""
                      />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-semibold">
                      ₹{(product.unitPrice * quantity).toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <Button variant="danger" size="sm" onClick={() => handleRemoveItem(product.id)}>
                        Remove
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>

      <section>
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Quote Summary</h3>
        <div className="flex justify-end mb-4">
          <div className="w-full md:w-1/2 lg:w-1/3 bg-gray-50 p-6 rounded-lg border border-gray-200 shadow-inner">
            <div className="flex justify-between items-center text-gray-700 py-2 border-b border-gray-200">
              <span className="font-semibold">Subtotal:</span>
              <span className="font-bold">₹{subtotal.toFixed(2)}</span>
            </div>

            <div className="py-2 border-b border-gray-200">
              <Input
                id="taxRate"
                label="Tax Rate (%)"
                type="number"
                step="0.01"
                min="0"
                value={(parseFloat(taxRate) * 100).toFixed(2)}
                onChange={(e) => setTaxRate((parseFloat(e.target.value) / 100).toFixed(4))}
                className="mb-0"
                error={errors.taxRate}
              />
              <div className="flex justify-between items-center text-gray-600 text-sm mt-1">
                <span>Tax Amount:</span>
                <span>₹{taxAmount.toFixed(2)}</span>
              </div>
            </div>

            <div className="py-2 border-b border-gray-200">
              <Input
                id="freightCost"
                label="Freight Cost (₹)"
                type="number"
                step="0.01"
                min="0"
                value={freightCost}
                onChange={(e) => setFreightCost(e.target.value)}
                className="mb-0"
                error={errors.freightCost}
                placeholder="0.00"
              />
            </div>

            <div className="flex justify-between items-center text-2xl font-bold text-blue-700 pt-4 mt-2">
              <span>Total:</span>
              <span>₹{total.toFixed(2)}</span>
            </div>
          </div>
        </div>
        <div className="flex justify-center mt-6">
          <Button variant="primary" size="lg" onClick={generateQuote}>
            Generate Quotation
          </Button>
        </div>
      </section>
    </div>
  );
};

export default QuoteBuilder;

import React, { useState } from 'react';
import { Product, QuoteItem, Quotation } from '../types';
import Input from './Input';
import Textarea from './Textarea';
import Button from './Button';

interface QuoteBuilderProps {
  products: Product[];
  onGenerateQuote: (quotation: Quotation) => void;
}

const QuoteBuilder: React.FC<QuoteBuilderProps> = ({ products, onGenerateQuote }) => {
  const [clientName, setClientName] = useState('');
  const [clientEmail, setClientEmail] = useState('');
  const [clientAddress, setClientAddress] = useState('');
  const [taxRate, setTaxRate] = useState<string>('0.05');
  const [freightCost, setFreightCost] = useState<string>('0');
  // Use explicit typing for the Map to avoid 'unknown' inference in callbacks
  const [selectedItems, setSelectedItems] = useState<Map<string, { product: Product; quantity: number }>>(new Map());
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const handleAddItem = (product: Product) => {
    setSelectedItems((prev) => {
      // Added explicit generic types to Map constructor to avoid unknown inference
      const newItems = new Map<string, { product: Product; quantity: number }>(prev);
      const existing = newItems.get(product.id);
      if (existing) {
        newItems.set(product.id, { product: existing.product, quantity: existing.quantity + 1 });
      } else {
        newItems.set(product.id, { product, quantity: 1 });
      }
      return newItems;
    });
  };

  const handleUpdateQuantity = (productId: string, quantity: number) => {
    setSelectedItems((prev) => {
      // Added explicit generic types to Map constructor to avoid unknown inference
      const newItems = new Map<string, { product: Product; quantity: number }>(prev);
      const existing = newItems.get(productId);
      if (existing) {
        if (quantity <= 0) {
          newItems.delete(productId);
        } else {
          newItems.set(productId, { product: existing.product, quantity });
        }
      }
      return newItems;
    });
  };

  const handleRemoveItem = (productId: string) => {
    setSelectedItems((prev) => {
      // Added explicit generic types to Map constructor to avoid unknown inference
      const newItems = new Map<string, { product: Product; quantity: number }>(prev);
      newItems.delete(productId);
      return newItems;
    });
  };

  const validate = () => {
    const newErrors: { [key: string]: string } = {};
    if (!clientName.trim()) newErrors.clientName = 'Client name is required.';
    if (selectedItems.size === 0) newErrors.items = 'At least one product must be added to the quotation.';
    if (isNaN(parseFloat(taxRate)) || parseFloat(taxRate) < 0) {
      newErrors.taxRate = 'Tax rate must be a non-negative number.';
    }
    if (isNaN(parseFloat(freightCost)) || parseFloat(freightCost) < 0) {
      newErrors.freightCost = 'Freight cost must be a non-negative number.';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const generateQuote = () => {
    if (!validate()) {
      alert('Please correct the errors before generating the quote.');
      return;
    }

    const items: QuoteItem[] = Array.from(selectedItems.values()).map(({ product, quantity }) => ({
      productId: product.id,
      name: product.name,
      description: product.description,
      unitPrice: product.unitPrice,
      quantity,
      lineTotal: product.unitPrice * quantity,
      image: product.image,
    }));

    const subtotal = items.reduce((sum: number, item: QuoteItem) => sum + item.lineTotal, 0);
    const parsedTaxRate = parseFloat(taxRate);
    const parsedFreight = parseFloat(freightCost) || 0;
    const taxAmount = subtotal * parsedTaxRate;
    const total = subtotal + taxAmount + parsedFreight;

    const newQuotation: Quotation = {
      id: Date.now().toString(),
      quoteNumber: `Q-${Date.now().toString().slice(-6)}`,
      date: new Date().toLocaleDateString('en-IN'),
      clientName,
      clientEmail: clientEmail.trim() || undefined,
      clientAddress: clientAddress.trim() || undefined,
      items,
      subtotal,
      taxRate: parsedTaxRate,
      taxAmount,
      freightCost: parsedFreight,
      total,
    };

    onGenerateQuote(newQuotation);
    setClientName('');
    setClientEmail('');
    setClientAddress('');
    setTaxRate('0.05');
    setFreightCost('0');
    setSelectedItems(new Map());
    setErrors({});
  };

  // Explicitly type derived values to fix 'unknown' arithmetic operation errors
  const currentQuoteItems: { product: Product; quantity: number }[] = Array.from(selectedItems.values());
  const subtotal: number = currentQuoteItems.reduce((sum: number, item) => sum + item.product.unitPrice * item.quantity, 0);
  const parsedTaxRate = parseFloat(taxRate);
  const parsedFreightValue = parseFloat(freightCost);
  const taxAmount: number = subtotal * (isNaN(parsedTaxRate) ? 0 : parsedTaxRate);
  const total: number = subtotal + taxAmount + (isNaN(parsedFreightValue) ? 0 : parsedFreightValue);

  return (
    <div className="bg-white p-6 rounded-lg shadow-md mb-8 border border-gray-100">
      <h2 className="text-2xl font-bold mb-6 text-center text-gray-800">Create New Quotation</h2>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Client Details</h3>
        <Input
          id="clientName"
          label="Client Name"
          type="text"
          value={clientName}
          onChange={(e) => setClientName(e.target.value)}
          placeholder="e.g., Acme Corp."
          error={errors.clientName}
        />
        <Input
          id="clientEmail"
          label="Client Email (Optional)"
          type="email"
          value={clientEmail}
          onChange={(e) => setClientEmail(e.target.value)}
          placeholder="e.g., contact@acmecorp.com"
        />
        <Textarea
          id="clientAddress"
          label="Client Address (Optional)"
          value={clientAddress}
          onChange={(e) => setClientAddress(e.target.value)}
          placeholder="123 Main St, Anytown, India"
        />
      </section>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Available Products</h3>
        {products.length === 0 ? (
          <p className="text-gray-600">No products available. Please add products in the 'Manage Products' section.</p>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            {products.map((product) => (
              <div key={product.id} className="border border-gray-200 rounded-lg flex flex-col justify-between hover:border-blue-300 transition-colors bg-white overflow-hidden shadow-sm">
                <div className="relative pt-[177.77%] bg-gray-100 border-b border-gray-200">
                  <div className="absolute inset-0">
                    {product.image ? (
                      <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-gray-300">
                        <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                        </svg>
                      </div>
                    )}
                  </div>
                </div>
                <div className="p-4">
                  <h4 className="font-bold text-gray-900 truncate">{product.name}</h4>
                  <p className="text-xs text-gray-500 mb-2 line-clamp-1 h-4">{product.description || ''}</p>
                  <p className="text-lg font-extrabold text-blue-700">₹{product.unitPrice.toLocaleString('en-IN')}</p>
                  <Button size="sm" onClick={() => handleAddItem(product)} className="mt-4 w-full">
                    Add to Quote
                  </Button>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="mb-8">
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Current Quote Items</h3>
        {errors.items && <p className="mb-4 text-sm text-red-600 font-medium">{errors.items}</p>}
        {selectedItems.size === 0 ? (
          <p className="text-gray-600 italic">No items added to the quote yet.</p>
        ) : (
          <div className="overflow-x-auto border border-gray-100 rounded-lg">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Product
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Unit Price
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Quantity
                  </th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Line Total
                  </th>
                  <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {currentQuoteItems.map(({ product, quantity }) => (
                  <tr key={product.id}>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      <div className="flex items-center">
                        <div className="h-12 w-7 rounded overflow-hidden mr-3 border border-gray-200 bg-gray-50 flex-shrink-0">
                          {product.image ? (
                            <img src={product.image} alt="" className="h-full w-full object-cover" />
                          ) : (
                            <div className="h-full w-full flex items-center justify-center text-gray-300">
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                              </svg>
                            </div>
                          )}
                        </div>
                        {product.name}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      ₹{product.unitPrice.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      <Input
                        id={`quantity-${product.id}`}
                        type="number"
                        min="1"
                        value={quantity.toString()}
                        onChange={(e) => handleUpdateQuantity(product.id, parseInt(e.target.value) || 0)}
                        className="w-20 p-1 text-center mb-0"
                        label=""
                      />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-semibold">
                      ₹{(product.unitPrice * quantity).toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <Button variant="danger" size="sm" onClick={() => handleRemoveItem(product.id)}>
                        Remove
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>

      <section>
        <h3 className="text-xl font-semibold mb-4 text-gray-700 border-b pb-2">Quote Summary</h3>
        <div className="flex justify-end mb-4">
          <div className="w-full md:w-1/2 lg:w-1/3 bg-gray-50 p-6 rounded-lg border border-gray-200 shadow-inner">
            <div className="flex justify-between items-center text-gray-700 py-2 border-b border-gray-200">
              <span className="font-semibold">Subtotal:</span>
              <span className="font-bold">₹{subtotal.toFixed(2)}</span>
