import React, { useState, useEffect, useCallback } from 'react';
import { Product, Quotation } from './types';
import { LOCAL_STORAGE_PRODUCTS_KEY, LOCAL_STORAGE_QUOTATIONS_KEY } from './constants';
import ProductForm from './components/ProductForm';
import ProductList from './components/ProductList';
import QuoteBuilder from './components/QuoteBuilder';
import QuoteDisplay from './components/QuoteDisplay';
import Button from './components/Button';

enum View {
  PRODUCTS = 'products',
  CREATE_QUOTE = 'create-quote',
  VIEW_QUOTE = 'view-quote',
  ALL_QUOTES = 'all-quotes',
}

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [quotations, setQuotations] = useState<Quotation[]>([]);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [currentView, setCurrentView] = useState<View>(View.PRODUCTS);
  const [lastView, setLastView] = useState<View>(View.PRODUCTS);
  const [selectedQuotation, setSelectedQuotation] = useState<Quotation | null>(null);

  const [isInitialized, setIsInitialized] = useState(false);

  // Load data on mount
  useEffect(() => {
    try {
      const storedProducts = localStorage.getItem(LOCAL_STORAGE_PRODUCTS_KEY);
      if (storedProducts) {
        setProducts(JSON.parse(storedProducts));
      }

      const storedQuotations = localStorage.getItem(LOCAL_STORAGE_QUOTATIONS_KEY);
      if (storedQuotations) {
        setQuotations(JSON.parse(storedQuotations));
      }
    } catch (error) {
      console.error('Failed to load data from local storage:', error);
    } finally {
      setIsInitialized(true);
    }
  }, []);

  // Save products only after initialization
  useEffect(() => {
    if (isInitialized) {
      try {
        localStorage.setItem(LOCAL_STORAGE_PRODUCTS_KEY, JSON.stringify(products));
      } catch (e) {
        console.error('Storage failed. Might be out of space.', e);
      }
    }
  }, [products, isInitialized]);

  // Save quotations only after initialization
  useEffect(() => {
    if (isInitialized) {
      try {
        localStorage.setItem(LOCAL_STORAGE_QUOTATIONS_KEY, JSON.stringify(quotations));
      } catch (e) {
        console.error('Storage failed. Might be out of space.', e);
      }
    }
  }, [quotations, isInitialized]);

  const navigateTo = useCallback((view: View) => {
    setLastView(currentView);
    setCurrentView(view);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [currentView]);

  const handleAddOrUpdateProduct = useCallback((product: Product) => {
    setProducts((prevProducts) => {
      const existingIndex = prevProducts.findIndex((p) => p.id === product.id);
      if (existingIndex > -1) {
        const updatedProducts = [...prevProducts];
        updatedProducts[existingIndex] = product;
        return updatedProducts;
      } else {
        return [...prevProducts, product];
      }
    });
    setEditingProduct(null);
    navigateTo(View.PRODUCTS);
  }, [navigateTo]);

  const handleDeleteProduct = useCallback((id: string) => {
    if (window.confirm('Are you sure you want to delete this product? It will be removed from your product list.')) {
      setProducts((prevProducts) => prevProducts.filter((p) => p.id !== id));
    }
  }, []);

  const handleGenerateQuotation = useCallback((quotation: Quotation) => {
    setQuotations((prevQuotations) => [...prevQuotations, quotation]);
    setSelectedQuotation(quotation);
    navigateTo(View.VIEW_QUOTE);
  }, [navigateTo]);

  const handleEditProduct = useCallback((product: Product) => {
    setEditingProduct(product);
    navigateTo(View.PRODUCTS);
  }, [navigateTo]);

  const handleViewQuote = useCallback((quote: Quotation) => {
    setSelectedQuotation(quote);
    navigateTo(View.VIEW_QUOTE);
  }, [navigateTo]);

  const handleBackFromDisplay = useCallback(() => {
    setSelectedQuotation(null);
    // If we came from 'All Quotes', go back there. Otherwise go to 'Create'.
    if (lastView === View.ALL_QUOTES) {
      setCurrentView(View.ALL_QUOTES);
    } else {
      setCurrentView(View.CREATE_QUOTE);
    }
  }, [lastView]);

  const handleDeleteQuotation = useCallback((id: string) => {
    if (window.confirm('Are you sure you want to delete this quotation?')) {
      setQuotations((prevQuotations) => prevQuotations.filter((q) => q.id !== id));
    }
  }, []);

  return (
    <div className="min-h-screen bg-gray-100 pb-16">
      <header className="bg-gradient-to-r from-blue-700 to-blue-900 text-white p-6 shadow-md sticky top-0 z-10 print-hidden">
        <div className="container mx-auto flex flex-col md:flex-row justify-between items-center">
          <div className="flex items-center mb-4 md:mb-0">
             <svg className="w-8 h-8 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
             </svg>
             <h1 className="text-3xl font-extrabold tracking-tight">QuoteFlow</h1>
          </div>
          <nav className="flex flex-wrap justify-center gap-2 sm:gap-4">
            <Button
              variant={currentView === View.PRODUCTS ? 'secondary' : 'outline'}
              className={currentView === View.PRODUCTS ? 'bg-white text-blue-800' : 'text-white border-white hover:bg-white/10'}
              onClick={() => {
                setEditingProduct(null);
                navigateTo(View.PRODUCTS);
              }}
            >
              Manage Products
            </Button>
            <Button
              variant={currentView === View.CREATE_QUOTE ? 'secondary' : 'outline'}
              className={currentView === View.CREATE_QUOTE ? 'bg-white text-blue-800' : 'text-white border-white hover:bg-white/10'}
              onClick={() => navigateTo(View.CREATE_QUOTE)}
            >
              Create Quotation
            </Button>
            <Button
              variant={currentView === View.ALL_QUOTES ? 'secondary' : 'outline'}
              className={currentView === View.ALL_QUOTES ? 'bg-white text-blue-800' : 'text-white border-white hover:bg-white/10'}
              onClick={() => navigateTo(View.ALL_QUOTES)}
            >
              All Quotations
            </Button>
          </nav>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8">
        {!isInitialized ? (
          <div className="flex justify-center items-center py-20">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-700"></div>
          </div>
        ) : (
          <>
            {currentView === View.PRODUCTS && (
              <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <ProductForm
                  onSave={handleAddOrUpdateProduct}
                  onCancel={() => setEditingProduct(null)}
                  editingProduct={editingProduct}
                />
                <ProductList
                  products={products}
                  onEdit={handleEditProduct}
                  onDelete={handleDeleteProduct}
                />
              </div>
            )}

            {currentView === View.CREATE_QUOTE && (
              <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                <QuoteBuilder products={products} onGenerateQuote={handleGenerateQuotation} />
              </div>
            )}

            {currentView === View.VIEW_QUOTE && selectedQuotation && (
              <div className="animate-in zoom-in duration-300">
                 <QuoteDisplay quotation={selectedQuotation} onBack={handleBackFromDisplay} />
              </div>
            )}

            {currentView === View.ALL_QUOTES && (
              <div className="bg-white p-6 rounded-lg shadow-md overflow-x-auto border border-gray-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <h2 className="text-2xl font-bold mb-6 text-center text-gray-800">All Generated Quotations</h2>
                {quotations.length === 0 ? (
                  <div className="text-center py-12">
                    <p className="text-gray-500 text-lg mb-4">No quotations generated yet.</p>
                    <Button onClick={() => navigateTo(View.CREATE_QUOTE)}>Create Your First Quote</Button>
                  </div>
                ) : (
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Quote #
                        </th>
                        <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Date
                        </th>
                        <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Client Name
                        </th>
                        <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Total
                        </th>
                        <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Actions
                        </th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {quotations.map((quote) => (
                        <tr key={quote.id} className="hover:bg-blue-50/50 transition-colors">
                          <td className="px-6 py-4 whitespace-nowrap text-sm font-bold text-blue-700 cursor-pointer hover:underline"
                              onClick={() => handleViewQuote(quote)}>
                            {quote.quoteNumber}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                            {quote.date}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-medium">
                            {quote.clientName}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-right text-sm text-gray-900 font-bold">
                            ₹{quote.total.toFixed(2)}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                            <Button variant="secondary" size="sm" onClick={() => handleViewQuote(quote)} className="mr-2">
                              View
                            </Button>
                            <Button variant="danger" size="sm" onClick={() => handleDeleteQuotation(quote.id)}>
                              Delete
                            </Button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
              </div>
            )}
          </>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import Input from './Input';
import Textarea from './Textarea';
import Button from './Button';
import { Product } from '../types';

interface ProductFormProps {
  onSave: (product: Product) => void;
  onCancel: () => void;
  editingProduct?: Product | null;
}

const ProductForm: React.FC<ProductFormProps> = ({ onSave, onCancel, editingProduct }) => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [unitPrice, setUnitPrice] = useState<string>('');
  const [image, setImage] = useState<string | undefined>(undefined);
  const [errors, setErrors] = useState<{ [key: string]: string }>({});
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (editingProduct) {
      setName(editingProduct.name);
      setDescription(editingProduct.description);
      setUnitPrice(editingProduct.unitPrice.toString());
      setImage(editingProduct.image);
    } else {
      setName('');
      setDescription('');
      setUnitPrice('');
      setImage(undefined);
    }
    setErrors({});
  }, [editingProduct]);

  const processImage = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          // Optimized resolution for vertical 9:16 portrait
          const TARGET_WIDTH = 360;
          const TARGET_HEIGHT = 640;
          canvas.width = TARGET_WIDTH;
          canvas.height = TARGET_HEIGHT;
          const ctx = canvas.getContext('2d');

          if (!ctx) {
            reject(new Error('Could not get canvas context'));
            return;
          }

          const targetRatio = TARGET_WIDTH / TARGET_HEIGHT;
          const imgRatio = img.width / img.height;
          let drawWidth, drawHeight, offsetX, offsetY;

          if (imgRatio > targetRatio) {
            drawHeight = img.height;
            drawWidth = img.height * targetRatio;
            offsetX = (img.width - drawWidth) / 2;
            offsetY = 0;
          } else {
            drawWidth = img.width;
            drawHeight = img.width / targetRatio;
            offsetX = 0;
            offsetY = (img.height - drawHeight) / 2;
          }

          ctx.drawImage(img, offsetX, offsetY, drawWidth, drawHeight, 0, 0, TARGET_WIDTH, TARGET_HEIGHT);
          resolve(canvas.toDataURL('image/jpeg', 0.8)); // Standard quality for mobile-ready thumbnails
        };
        img.onerror = () => reject(new Error('Failed to load image'));
        img.src = e.target?.result as string;
      };
      reader.onerror = () => reject(new Error('Failed to read file'));
      reader.readAsDataURL(file);
    });
  };

  const handleImageChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsProcessing(true);
      try {
        const processedImage = await processImage(file);
        setImage(processedImage);
      } catch (err) {
        console.error('Image processing error:', err);
        setErrors({ ...errors, image: 'Failed to process image.' });
      } finally {
        setIsProcessing(false);
      }
    }
  };

  const validate = () => {
    const newErrors: { [key: string]: string } = {};
    if (!name.trim()) newErrors.name = 'Product name is required.';
    if (!unitPrice) {
      newErrors.unitPrice = 'Unit price is required.';
    } else if (isNaN(parseFloat(unitPrice)) || parseFloat(unitPrice) <= 0) {
      newErrors.unitPrice = 'Unit price must be a positive number.';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      const newProduct: Product = {
        id: editingProduct ? editingProduct.id : Date.now().toString(),
        name,
        description,
        unitPrice: parseFloat(unitPrice),
        image,
      };
      onSave(newProduct);
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-md max-w-lg mx-auto mb-8 border border-gray-100">
      <h2 className="text-2xl font-bold mb-6 text-center text-gray-800">
        {editingProduct ? 'Edit Product' : 'Add New Product'}
      </h2>
      <form onSubmit={handleSubmit}>
        <div className="flex flex-col items-center mb-6">
          <div className="w-36 h-64 bg-gray-100 rounded-lg border-2 border-dashed border-gray-300 flex items-center justify-center overflow-hidden mb-3 relative group">
            {isProcessing && (
              <div className="absolute inset-0 bg-white/80 flex items-center justify-center z-10">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
              </div>
            )}
            {image ? (
              <img src={image} alt="Preview" className="w-full h-full object-cover" />
            ) : (
              <div className="text-center px-4">
                <svg className="w-10 h-10 text-gray-400 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                </svg>
                <p className="text-xs text-gray-400">Portrait Photo (9:16)</p>
              </div>
            )}
          </div>
          <input
            type="file"
            ref={fileInputRef}
            className="hidden"
            accept="image/*"
            onChange={handleImageChange}
          />
          <div className="flex flex-col items-center">
            <Button 
              type="button" 
              variant="outline" 
              size="sm" 
              onClick={() => fileInputRef.current?.click()}
              disabled={isProcessing}
            >
              {image ? 'Change Photo' : 'Upload Photo'}
            </Button>
            <p className="text-[10px] text-gray-400 mt-2 uppercase tracking-tight">Optimized for Vertical Specs</p>
          </div>
          {image && (
            <button 
              type="button" 
              className="text-red-500 text-xs mt-2 hover:underline"
              onClick={() => setImage(undefined)}
            >
              Remove Photo
            </button>
          )}
          {errors.image && <p className="text-red-500 text-xs mt-1">{errors.image}</p>}
        </div>

        <Input
          id="productName"
          label="Product Name"
          type="text"
          value={name}
          onChange={(e) => setName(e.target.value)}
          placeholder="e.g., Vertical Digital Display"
          error={errors.name}
        />
        <Textarea
          id="productDescription"
          label="Description"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          placeholder="Detailed description of the product."
        />
        <Input
          id="unitPrice"
          label="Unit Price (₹)"
          type="number"
          step="0.01"
          value={unitPrice}
          onChange={(e) => setUnitPrice(e.target.value)}
          placeholder="e.g., 5000.00"
          error={errors.unitPrice}
        />
        <div className="flex justify-end space-x-3 mt-6">
          <Button type="button" variant="secondary" onClick={onCancel}>
            Cancel
          </Button>
          <Button type="submit" variant="primary" disabled={isProcessing}>
            {editingProduct ? 'Update Product' : 'Add Product'}
          </Button>
        </div>
      </form>
    </div>
  );
};

